const query = $input.item.json.query || $input.item.json.input || '{}';
let data;
try { data = typeof query === 'string' ? JSON.parse(query) : query; } catch(e) { data = {}; }

// Pull session ID directly from the Chat trigger
const sessionKey = data.session_key || $('When chat message received').item.json.sessionId;
if (!sessionKey) return { error: 'session_key is required' };

const body = {
  p_session_key: sessionKey,
  p_business_name: data.businessName || null,
  p_niche: 'HVAC',
  p_stage: data.stage || 'New',
  p_lead_type: 'inbound_chat',
  p_issue_type: data.issue_type || null,
  p_equipment_type: data.equipment_type || null,
  p_urgency: data.urgency || null,
  p_system_down: data.system_down || false,
  p_name: data.name || null,
  p_phone: data.phone || null,
  p_email: data.email || null,
  p_service_address: data.service_address || null,
  p_zip: data.zip || null,
  p_preferred_time_window: data.preferred_time_window || null,
  p_priority: data.priority || null,
  p_consent_to_contact: data.consent_to_contact || false,
  p_chat_summary: data.chat_summary || null,
  p_place_id: data.placeId || null
};

// Use your n8n Cloud $vars exactly as named in your screenshot!
const supabaseUrl = $vars.SUPABASE_URL;
const supabaseKey = $vars.SUPABASE_SERVICE_ROLE_KEY;

if (!supabaseUrl || !supabaseUrl.startsWith('http')) return { error: 'Supabase URL is missing or invalid in vars' };

try {
  // Use n8n's native high-speed HTTP client with a 5 second timeout
  const result = await $helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/rest/v1/rpc/upsert_lead',
    headers: {
      'Content-Type': 'application/json',
      'apikey': supabaseKey,
      'Authorization': 'Bearer ' + supabaseKey
    },
    body: body,
    timeout: 5000 
  });
  return { success: true, lead: result };
} catch (error) {
  return { error: 'Upsert connection failed', details: error.message };
}

const now = new Date();
const day = now.getDay(), hour = now.getHours();
let open = false, next = 'Monday at 8:00 AM';
if (day >= 1 && day <= 5) {
  open = hour >= 8 && hour < 18;
  next = open ? 'Now' : (hour < 8 ? 'Today at 8:00 AM' : 'Tomorrow at 8:00 AM');
} else if (day === 6) {
  open = hour >= 9 && hour < 14;
  next = open ? 'Now' : 'Monday at 8:00 AM';
}
return {
  is_business_hours: open,
  current_time: now.toISOString(),
  day_of_week: ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'][day],
  next_available: next,
  message: open ? 'Within business hours.' : `After hours. Next available: ${next}. Emergency line available 24/7.`
};

let input = $input.first().json;

// FIX: If the AI Agent sends the data encoded as a string, parse it automatically
if (input.input && typeof input.input === 'string') {
    try {
        input = JSON.parse(input.input);
    } catch(e) {}
}

const errors = [];
if (!input.session_key) errors.push('session_key required');
if (!input.zip) errors.push('zip required');
if (!input.issue_type) errors.push('issue_type required');

return { json: { ...input, niche: 'hvac', valid: errors.length === 0, errors } };

const err = $input.first().json;
return { 
  json: {
    success: false,
    error: 'Validation failed',
    details: err.errors.join(', ')
  }
};

const input = $input.first().json;
const zip = input.zip || '';

// Add your serviceable ZIP codes here if you want to restrict service
const allowedZips = []; // Empty array means all ZIPs allowed for now

let serviceable = true;
if (allowedZips.length > 0 && !allowedZips.includes(zip)) {
  serviceable = false;
}

return {
  json: {
    ...input,
    serviceable: serviceable,
    service_message: serviceable ? 'In service area' : 'Out of service area'
  }
};

const input = $input.first().json;
const issue = (input.issue_type || '').toLowerCase();
const equip = (input.equipment_type || '').toLowerCase();
const urgency = (input.urgency || '').toLowerCase();

let low = 0;
let high = 0;
let action = '';
let cta = '';
let disclaimer = "This is a preliminary estimate range. Actual costs depend on an on-site diagnostic.";

// 1. REPLACEMENT LOGIC
if (issue.includes('replace') || issue.includes('install') || issue.includes('new')) {
    low = 4500;
    high = 8500;
    if (equip.includes('mini_split') || equip.includes('ductless')) {
       low = 3500; high = 6500;
    }
    action = 'schedule_consultation';
    cta = 'I highly recommend we schedule a free, no-obligation replacement consultation.';
}
// 2. MAINTENANCE LOGIC
else if (issue.includes('maintain') || issue.includes('tune') || issue.includes('clean')) {
    low = 89;
    high = 149;
    action = 'schedule_maintenance';
    cta = 'We can easily schedule a system tune-up and inspection for you.';
    disclaimer = "Standard maintenance pricing. Filters and required repairs are extra.";
}
// 3. REPAIR/DIAGNOSTIC LOGIC (Default)
else {
    low = 150;
    high = 600;
    action = 'schedule_diagnostic';
    cta = 'A technician needs to diagnose this on-site. The dispatch fee is typically $89, which is waived if you proceed with repairs.';
}

// 4. EMERGENCY MULTIPLIER
if (urgency.includes('emergency') || input.system_down === true) {
    action = 'dispatch_emergency';
    cta = 'Since this is an emergency, our on-call tech will be dispatched out as soon as possible.';
    low = Math.round(low * 1.5);
    high = Math.round(high * 1.5);
    disclaimer = "Emergency/After-hours dispatch rates apply. Final cost requires field assessment.";
}

return {
  json: {
    ...input,
    estimate_low: low,
    estimate_high: high,
    estimate_range: `$${low} - $${high}`,
    action: action,
    disclaimer: disclaimer,
    next_message: cta
  }
};

const result = $input.first().json;

return {
  json: {
    success: true,
    estimate_data: {
        low: result.estimate_low,
        high: result.estimate_high,
        range: result.estimate_range,
        action: result.action
    },
    disclaimer: result.disclaimer,
    summary: `Based on what you've told me, you can expect costs around ${result.estimate_range}. ${result.next_message}`
  }
};
